function onLoad() {

	// STRY0107400
	if(g_form.getValue('state') == -6 && g_form.getValue('parent') + '' != ''){
		g_form.showFieldMsg('tasker_process_instance',getMessage('Tasker - Draft task(s) can only be published from the top task.'),'info');
	}

}
